script:
frappe.ui.form.on("Hostel Fee", {

    refresh(frm) {

        // Default Payment Status
        if (frm.is_new() && !frm.doc.payment_status) {
            frm.set_value("payment_status", "Pending");
        }

    },

    hostel_admission(frm) {

        if (!frm.doc.hostel_admission) {
            return;
        }

        frappe.db.get_doc("Hostel Admission", frm.doc.hostel_admission)
            .then(doc => {

                frm.set_value("student", doc.student);
                frm.set_value("hostel", doc.hostel);
                frm.set_value("academic_year", doc.academic_year);
                frm.set_value("amount", doc.monthly_fee);

            });

    }

});
